  int sync_ref = get_softmodem_params()->sync_ref;

  if (get_softmodem_params()->sl_mode == 2) {
    //Preparation of the Sidelink PRE-Configuration message
    configure_NR_SL_Preconfig(rrc, sync_ref);

  }
}

