  snprintf(aprefix, sizeof(aprefix), "%s.[%i]", SL_CONFIG_STRING_SL_PRECONFIGURATION, 0);
  config_getlist(config_get_if(), &SL_SYNCFGParamList, NULL, 0, aprefix);
